HOME_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>Teacher Proforma Verification — Chikiti Block</title>\n<style>\n  :root{--navy:#0d2366;--steel:#1f4e79;--sky:#dce6f1;--green:#2e7d32;--amber:#f57f17;--red:#c62828;--white:#fff;--grey:#f5f7fa}\n  *{box-sizing:border-box;margin:0;padding:0}\n  body{font-family:\'Segoe UI\',Arial,sans-serif;background:var(--grey);min-height:100vh;display:flex;flex-direction:column}\n  /* ── Header ── */\n  header{background:linear-gradient(135deg,var(--navy) 0%,var(--steel) 100%);color:var(--white);padding:0}\n  .header-inner{max-width:1000px;margin:auto;padding:18px 24px;display:flex;align-items:center;gap:18px}\n  .header-logo{width:58px;height:58px;background:var(--white);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:28px;flex-shrink:0}\n  .header-text h1{font-size:1.35rem;font-weight:700;letter-spacing:.3px}\n  .header-text p{font-size:.82rem;opacity:.85;margin-top:3px}\n  /* ── Hero ── */\n  .hero{background:linear-gradient(135deg,#e8f0fe 0%,#d0e8ff 100%);padding:52px 24px 44px;text-align:center}\n  .hero h2{font-size:1.9rem;color:var(--navy);font-weight:700;margin-bottom:10px}\n  .hero p{color:#444;font-size:1rem;max-width:620px;margin:auto;line-height:1.6}\n  /* ── Cards ── */\n  .cards{max-width:800px;margin:-28px auto 0;padding:0 24px 60px;display:grid;grid-template-columns:1fr 1fr;gap:24px}\n  @media(max-width:600px){.cards{grid-template-columns:1fr}}\n  .card{background:var(--white);border-radius:14px;box-shadow:0 4px 20px rgba(0,0,0,.1);padding:36px 28px;text-align:center;transition:transform .2s,box-shadow .2s;text-decoration:none;color:inherit;display:block}\n  .card:hover{transform:translateY(-4px);box-shadow:0 8px 32px rgba(0,0,0,.15)}\n  .card-icon{font-size:3rem;margin-bottom:14px}\n  .card h3{font-size:1.2rem;color:var(--navy);font-weight:700;margin-bottom:8px}\n  .card p{font-size:.88rem;color:#555;line-height:1.5;margin-bottom:20px}\n  .btn{display:inline-block;padding:11px 28px;border-radius:8px;font-size:.92rem;font-weight:600;text-decoration:none;transition:opacity .2s}\n  .btn-teacher{background:var(--navy);color:var(--white)}\n  .btn-admin{background:var(--steel);color:var(--white)}\n  .btn:hover{opacity:.88}\n  /* ── Info bar ── */\n  .info-bar{background:var(--navy);color:var(--white);text-align:center;padding:14px 24px;font-size:.84rem;opacity:.92}\n  .info-bar span{margin:0 14px}\n  /* ── Footer ── */\n  footer{margin-top:auto;background:#1a1a2e;color:#aaa;text-align:center;padding:16px;font-size:.8rem}\n</style>\n</head>\n<body>\n\n<header>\n  <div class="header-inner">\n    <div class="header-logo">🏫</div>\n    <div class="header-text">\n      <h1>Teacher Proforma Verification System</h1>\n      <p>Chikiti Block, Ganjam District, Odisha &nbsp;|&nbsp; 2026</p>\n    </div>\n  </div>\n</header>\n\n<div class="hero">\n  <h2>Welcome to the Verification Portal</h2>\n  <p>Teachers can log in to view, verify and update their proforma data. Administrators can manage all records and export updated data to Excel.</p>\n</div>\n\n<div class="cards">\n  <a class="card" href="/teacher/login">\n    <div class="card-icon">👨\u200d🏫</div>\n    <h3>Teacher Login</h3>\n    <p>Select your school and enter your date of birth to access and verify your proforma data.</p>\n    <span class="btn btn-teacher">Teacher Login →</span>\n  </a>\n\n  <a class="card" href="/admin/login">\n    <div class="card-icon">🛡️</div>\n    <h3>Admin Login</h3>\n    <p>Authorised administrators can manage all teacher records, view updates and export data.</p>\n    <span class="btn btn-admin">Admin Login →</span>\n  </a>\n</div>\n\n<div class="info-bar">\n  <span>📊 Total Teachers: 43</span>\n  <span>🏫 Schools: 12</span>\n  <span>📋 Proformas I – VII</span>\n  <span>🔒 Secure &amp; Encrypted</span>\n</div>\n\n<footer>\n  &copy; 2026 Chikiti Block Education Office, Ganjam District &nbsp;|&nbsp; Teacher Proforma Verification System\n</footer>\n\n</body>\n</html>\n'

TEACHER_LOGIN_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>Teacher Login — Chikiti Block</title>\n<style>\n  :root{--navy:#0d2366;--steel:#1f4e79;--sky:#dce6f1;--green:#2e7d32;--amber:#f57f17;--red:#c62828}\n  *{box-sizing:border-box;margin:0;padding:0}\n  body{font-family:\'Segoe UI\',Arial,sans-serif;background:linear-gradient(135deg,#e8f0fe 0%,#c8deff 100%);min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:24px}\n  .back-link{position:fixed;top:16px;left:16px;color:var(--navy);text-decoration:none;font-size:.9rem;font-weight:600;background:rgba(255,255,255,.85);padding:8px 14px;border-radius:8px;box-shadow:0 2px 8px rgba(0,0,0,.1)}\n  .back-link:hover{background:var(--white)}\n  /* Card */\n  .card{background:#fff;border-radius:18px;box-shadow:0 8px 40px rgba(13,35,102,.15);padding:44px 40px 40px;max-width:480px;width:100%}\n  .logo{text-align:center;margin-bottom:28px}\n  .logo .icon{font-size:3.2rem;margin-bottom:8px}\n  .logo h1{font-size:1.5rem;color:var(--navy);font-weight:700}\n  .logo p{font-size:.85rem;color:#666;margin-top:4px}\n  /* Form */\n  .field{margin-bottom:20px}\n  label{display:block;font-size:.88rem;font-weight:600;color:var(--steel);margin-bottom:6px}\n  select,input[type=text],input[type=date]{\n    width:100%;padding:11px 14px;border:2px solid #d0daf0;border-radius:9px;\n    font-size:.95rem;color:#222;background:#fdfdff;transition:border-color .2s;outline:none}\n  select:focus,input:focus{border-color:var(--navy)}\n  .hint{font-size:.78rem;color:#888;margin-top:5px}\n  .btn-login{\n    width:100%;padding:14px;background:linear-gradient(135deg,var(--navy),var(--steel));\n    color:#fff;border:none;border-radius:10px;font-size:1rem;font-weight:700;\n    cursor:pointer;transition:opacity .2s;margin-top:8px}\n  .btn-login:hover{opacity:.9}\n  .btn-login:disabled{opacity:.6;cursor:not-allowed}\n  /* Error / info */\n  .alert{padding:12px 16px;border-radius:9px;font-size:.88rem;margin-bottom:16px;display:none}\n  .alert.error{background:#ffeaea;color:var(--red);border:1px solid #ffcdd2}\n  .alert.success{background:#e8f5e9;color:var(--green);border:1px solid #c8e6c9}\n  .alert.show{display:block}\n  /* Spinner */\n  .spinner{display:none;width:20px;height:20px;border:3px solid rgba(255,255,255,.4);border-top-color:#fff;border-radius:50%;animation:spin .7s linear infinite;margin:auto}\n  @keyframes spin{to{transform:rotate(360deg)}}\n  /* Info box */\n  .info-box{background:#f0f4ff;border-left:4px solid var(--navy);border-radius:0 8px 8px 0;padding:12px 14px;margin-bottom:22px;font-size:.84rem;color:var(--navy);line-height:1.5}\n</style>\n</head>\n<body>\n\n<a class="back-link" href="/">← Home</a>\n\n<div class="card">\n  <div class="logo">\n    <div class="icon">👨\u200d🏫</div>\n    <h1>Teacher Login</h1>\n    <p>Chikiti Block, Ganjam District — 2026</p>\n  </div>\n\n  <div class="info-box">\n    🔐 Select your school and enter your date of birth (as recorded in the office). Your proforma data will be displayed for verification.\n  </div>\n\n  <div class="alert error" id="alertBox"></div>\n\n  <div class="field">\n    <label for="schoolSelect">🏫 Select Your School *</label>\n    <select id="schoolSelect">\n      <option value="">— Choose your school —</option>\n      {% for school in schools %}\n      <option value="{{ school }}">{{ school }}</option>\n      {% endfor %}\n    </select>\n  </div>\n\n  <div class="field">\n    <label for="dobInput">📅 Date of Birth *</label>\n    <input type="date" id="dobInput" placeholder="DD/MM/YYYY">\n    <div class="hint">Enter your date of birth as registered in the proforma.</div>\n  </div>\n\n  <button class="btn-login" id="loginBtn" onclick="doLogin()">\n    <span id="btnText">Login &amp; View My Data →</span>\n    <div class="spinner" id="spinner"></div>\n  </button>\n</div>\n\n<script>\nasync function doLogin(){\n  const school = document.getElementById(\'schoolSelect\').value.trim();\n  const dobRaw  = document.getElementById(\'dobInput\').value.trim();\n  const alert   = document.getElementById(\'alertBox\');\n  alert.className = \'alert\';\n\n  if(!school){ showErr(\'Please select your school.\'); return; }\n  if(!dobRaw){  showErr(\'Please enter your date of birth.\'); return; }\n\n  // Convert YYYY-MM-DD (from date input) → DD/MM/YYYY\n  const parts = dobRaw.split(\'-\');\n  const dob   = parts.length===3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : dobRaw;\n\n  setBusy(true);\n  try{\n    const res  = await fetch(\'/teacher/login\',{\n      method:\'POST\',\n      headers:{\'Content-Type\':\'application/json\'},\n      body: JSON.stringify({school, dob})\n    });\n    const data = await res.json();\n    if(data.success){\n      window.location.href = \'/teacher/dashboard\';\n    } else {\n      showErr(data.error || \'Login failed. Please check your details.\');\n    }\n  } catch(e){ showErr(\'Network error. Please try again.\'); }\n  finally{ setBusy(false); }\n}\n\nfunction showErr(msg){\n  const a = document.getElementById(\'alertBox\');\n  a.textContent = msg;\n  a.className = \'alert error show\';\n}\nfunction setBusy(on){\n  document.getElementById(\'loginBtn\').disabled = on;\n  document.getElementById(\'btnText\').style.display = on?\'none\':\'block\';\n  document.getElementById(\'spinner\').style.display = on?\'block\':\'none\';\n}\n\n// Allow Enter key\ndocument.addEventListener(\'keydown\', e=>{ if(e.key===\'Enter\') doLogin(); });\n</script>\n</body>\n</html>\n'

TEACHER_DASHBOARD_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>My Proforma Data — Teacher Dashboard</title>\n<style>\n  :root{--navy:#0d2366;--steel:#1f4e79;--sky:#dce6f1;--green:#2e7d32;--amber:#e65100;--red:#c62828;--grey:#f5f7fa}\n  *{box-sizing:border-box;margin:0;padding:0}\n  body{font-family:\'Segoe UI\',Arial,sans-serif;background:var(--grey);min-height:100vh}\n\n  /* ── Top bar ── */\n  .topbar{background:linear-gradient(135deg,var(--navy),var(--steel));color:#fff;padding:14px 24px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px}\n  .topbar-left{display:flex;align-items:center;gap:12px}\n  .topbar-left .icon{font-size:1.8rem}\n  .topbar-left h1{font-size:1.1rem;font-weight:700}\n  .topbar-left p{font-size:.78rem;opacity:.8}\n  .topbar-right{display:flex;gap:10px;align-items:center}\n  .school-badge{background:rgba(255,255,255,.15);padding:7px 14px;border-radius:20px;font-size:.82rem}\n  .btn-logout{background:rgba(255,255,255,.12);color:#fff;border:1px solid rgba(255,255,255,.3);padding:8px 16px;border-radius:8px;cursor:pointer;font-size:.85rem;text-decoration:none;transition:background .2s}\n  .btn-logout:hover{background:rgba(255,255,255,.25)}\n\n  /* ── Container ── */\n  .container{max-width:1100px;margin:0 auto;padding:24px 18px 60px}\n\n  /* ── Progress bar ── */\n  .progress-wrap{background:#fff;border-radius:12px;box-shadow:0 2px 12px rgba(0,0,0,.07);padding:18px 22px;margin-bottom:22px}\n  .progress-label{font-size:.85rem;color:#555;margin-bottom:6px}\n  .progress-bar{height:9px;background:#e0e0e0;border-radius:5px;overflow:hidden}\n  .progress-fill{height:100%;background:linear-gradient(90deg,#2196f3,#0d2366);border-radius:5px;transition:width .6s}\n  .progress-stats{display:flex;gap:18px;margin-top:12px;flex-wrap:wrap}\n  .stat-item{font-size:.82rem;color:#555}\n  .stat-item strong{color:var(--navy)}\n\n  /* ── Teacher card ── */\n  .teacher-card{background:#fff;border-radius:14px;box-shadow:0 3px 18px rgba(0,0,0,.09);margin-bottom:28px;overflow:hidden}\n  .teacher-card-header{background:linear-gradient(135deg,var(--navy),var(--steel));color:#fff;padding:18px 24px;display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap}\n  .teacher-name{font-size:1.15rem;font-weight:700}\n  .teacher-meta{font-size:.82rem;opacity:.85;margin-top:3px}\n  .status-badge{padding:6px 16px;border-radius:20px;font-size:.82rem;font-weight:700;text-transform:uppercase}\n  .badge-PENDING{background:#fff3e0;color:#e65100;border:1.5px solid #ffcc02}\n  .badge-VERIFIED{background:#e8f5e9;color:#1b5e20;border:1.5px solid #66bb6a}\n  .badge-UPDATED{background:#e3f2fd;color:#0d47a1;border:1.5px solid #42a5f5}\n\n  /* ── Field groups ── */\n  .teacher-body{padding:22px 24px}\n  .field-group{margin-bottom:22px}\n  .group-title{font-size:.92rem;font-weight:700;color:var(--steel);margin-bottom:12px;padding-bottom:6px;border-bottom:2px solid var(--sky);display:flex;align-items:center;gap:6px}\n  .fields-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px}\n  .field-item{border:1.5px solid #e8edf5;border-radius:9px;padding:10px 13px;background:#fdfdff;transition:border-color .2s}\n  .field-item.changed{border-color:#1976d2;background:#f0f6ff}\n  .field-label{font-size:.75rem;font-weight:600;color:#888;text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px}\n  .field-value{font-size:.92rem;color:#222;word-break:break-word}\n  .field-input{width:100%;border:none;background:transparent;font-size:.92rem;color:#1a237e;outline:none;font-family:inherit;padding:0}\n  .field-input::placeholder{color:#bbb}\n\n  /* ── Action buttons ── */\n  .action-bar{padding:16px 24px 22px;background:#f8f9ff;border-top:1px solid #e8edf5;display:flex;gap:12px;flex-wrap:wrap;align-items:center}\n  .btn{padding:10px 22px;border-radius:9px;font-size:.9rem;font-weight:600;border:none;cursor:pointer;transition:all .2s;display:flex;align-items:center;gap:7px}\n  .btn-verify{background:linear-gradient(135deg,#2e7d32,#388e3c);color:#fff}\n  .btn-verify:hover{opacity:.9;transform:translateY(-1px)}\n  .btn-save{background:linear-gradient(135deg,#1565c0,#1976d2);color:#fff}\n  .btn-save:hover{opacity:.9;transform:translateY(-1px)}\n  .btn-edit{background:#fff;color:var(--navy);border:2px solid var(--navy)}\n  .btn-edit:hover{background:var(--sky)}\n  .btn-cancel{background:#fff;color:#666;border:2px solid #ddd}\n  .btn-cancel:hover{background:#f5f5f5}\n  .btn:disabled{opacity:.55;cursor:not-allowed;transform:none}\n  .changes-count{font-size:.82rem;color:#1565c0;background:#e3f2fd;padding:5px 12px;border-radius:20px;margin-left:auto}\n\n  /* ── Success banner ── */\n  .success-banner{background:#e8f5e9;border:1.5px solid #81c784;color:#1b5e20;border-radius:10px;padding:13px 18px;margin-bottom:18px;display:flex;align-items:center;gap:10px;display:none}\n  .success-banner.show{display:flex}\n\n  /* ── Toast ── */\n  .toast{position:fixed;bottom:28px;right:28px;padding:14px 22px;border-radius:10px;color:#fff;font-size:.9rem;font-weight:600;z-index:9999;opacity:0;transform:translateY(20px);transition:all .35s;pointer-events:none;max-width:340px;box-shadow:0 6px 24px rgba(0,0,0,.2)}\n  .toast.show{opacity:1;transform:translateY(0)}\n  .toast.success{background:#2e7d32}\n  .toast.error{background:#c62828}\n  .toast.info{background:#0d2366}\n\n  /* ── Spinner ── */\n  .spinner{width:16px;height:16px;border:2.5px solid rgba(255,255,255,.4);border-top-color:#fff;border-radius:50%;animation:spin .7s linear infinite}\n  @keyframes spin{to{transform:rotate(360deg)}}\n\n  /* ── Loading overlay ── */\n  #loadingOverlay{position:fixed;inset:0;background:rgba(255,255,255,.85);display:flex;align-items:center;justify-content:center;z-index:9000;flex-direction:column;gap:14px}\n  #loadingOverlay .sp{width:44px;height:44px;border:5px solid #dce6f1;border-top-color:var(--navy);border-radius:50%;animation:spin 1s linear infinite}\n  #loadingOverlay p{color:var(--navy);font-weight:600}\n\n  /* ── Edit mode indicator ── */\n  .edit-mode-bar{background:#fff3cd;border:1px solid #ffc107;color:#856404;padding:10px 16px;border-radius:8px;font-size:.85rem;margin-bottom:14px;display:none;align-items:center;gap:8px}\n  .edit-mode-bar.show{display:flex}\n\n  @media(max-width:600px){\n    .topbar{flex-direction:column;align-items:flex-start}\n    .fields-grid{grid-template-columns:1fr}\n    .action-bar{justify-content:center}\n  }\n</style>\n</head>\n<body>\n\n<!-- Loading Overlay -->\n<div id="loadingOverlay">\n  <div class="sp"></div>\n  <p>Loading your proforma data…</p>\n</div>\n\n<!-- Top Bar -->\n<div class="topbar">\n  <div class="topbar-left">\n    <div class="icon">👨\u200d🏫</div>\n    <div>\n      <h1>My Proforma Data</h1>\n      <p>Chikiti Block Verification Portal · 2026</p>\n    </div>\n  </div>\n  <div class="topbar-right">\n    <div class="school-badge">🏫 {{ school }}</div>\n    <a href="/teacher/logout" class="btn-logout">🚪 Logout</a>\n  </div>\n</div>\n\n<!-- Main container -->\n<div class="container">\n\n  <!-- Progress bar -->\n  <div class="progress-wrap" id="progressWrap" style="display:none">\n    <div class="progress-label">Verification Progress</div>\n    <div class="progress-bar"><div class="progress-fill" id="progressFill" style="width:0%"></div></div>\n    <div class="progress-stats" id="progressStats"></div>\n  </div>\n\n  <!-- Teacher records inserted here -->\n  <div id="teacherRecords"></div>\n\n  <!-- No data message -->\n  <div id="noData" style="display:none;background:#fff;border-radius:14px;padding:40px;text-align:center;color:#999;font-size:1.1rem">\n    ⚠️ No records found. Please <a href="/teacher/logout">logout</a> and try again.\n  </div>\n\n</div>\n\n<!-- Toast -->\n<div class="toast" id="toast"></div>\n\n<script>\n/* ── State ── */\nlet allTeachers = [], fieldLabels = {}, fieldGroups = [];\nlet editModes = {}; // { "NAME||PROFORMA": bool }\n\n/* ── Boot ── */\nwindow.onload = async () => {\n  try {\n    const res  = await fetch(\'/api/teacher/mydata\');\n    const data = await res.json();\n    allTeachers = data.teachers || [];\n    fieldLabels = data.field_labels || {};\n    fieldGroups = data.field_groups || [];\n    renderAll();\n  } catch(e) {\n    document.getElementById(\'noData\').style.display = \'block\';\n  } finally {\n    document.getElementById(\'loadingOverlay\').style.display = \'none\';\n  }\n};\n\n/* ── Render all teachers ── */\nfunction renderAll(){\n  if(!allTeachers.length){ document.getElementById(\'noData\').style.display=\'block\'; return; }\n\n  // Progress\n  const total = allTeachers.length;\n  const done  = allTeachers.filter(t=>t.status===\'VERIFIED\'||t.status===\'UPDATED\').length;\n  if(total > 1){\n    document.getElementById(\'progressWrap\').style.display = \'block\';\n    document.getElementById(\'progressFill\').style.width = `${Math.round(done/total*100)}%`;\n    document.getElementById(\'progressStats\').innerHTML =\n      allTeachers.map(t=>`<div class="stat-item"><strong>${t.teacher_name}</strong>: \n        <span style="color:${statusColor(t.status)}">${t.status}</span></div>`).join(\'\');\n  }\n\n  const container = document.getElementById(\'teacherRecords\');\n  container.innerHTML = \'\';\n  allTeachers.forEach((t,i)=>{\n    container.insertAdjacentHTML(\'beforeend\', buildCard(t, i));\n  });\n}\n\nfunction statusColor(s){ return s===\'VERIFIED\'?\'#2e7d32\':s===\'UPDATED\'?\'#1565c0\':\'#e65100\'; }\n\n/* ── Build one teacher card ── */\nfunction buildCard(t, idx){\n  const key  = cardKey(t);\n  const isEdit = editModes[key] || false;\n  const pf   = t.proforma || \'\';\n  const ts   = t.last_updated ? ` · Last updated: ${t.last_updated}` : \'\';\n  const chCount = (t.change_history||[]).length;\n\n  let groupsHtml = \'\';\n  for(const grp of fieldGroups){\n    let fieldsHtml = \'\';\n    for(const fk of grp.fields){\n      if(fk===\'teacher_name\'||fk===\'sl_no\') continue;\n      const label = fieldLabels[fk] || fk;\n      const val   = t[fk] || \'\';\n      const isDate = fk.startsWith(\'date_\')||fk===\'dob\';\n      fieldsHtml += `\n        <div class="field-item" id="fi_${idx}_${fk}">\n          <div class="field-label">${label}</div>\n          ${isEdit ? `<input class="field-input" id="inp_${idx}_${fk}" \n            type="${isDate?\'text\':\'text\'}" value="${escHtml(val)}" \n            placeholder="${isDate?\'DD/MM/YYYY\':\'\'}"\n            oninput="markChanged(${idx},\'${fk}\')">` \n            : `<div class="field-value">${escHtml(val)||\'<span style="color:#bbb">—</span>\'}</div>`}\n        </div>`;\n    }\n    groupsHtml += `\n      <div class="field-group">\n        <div class="group-title">${grp.title}</div>\n        <div class="fields-grid">${fieldsHtml}</div>\n      </div>`;\n  }\n\n  // Determine action bar content based on status & edit mode\n  let actionHtml = \'\';\n  if(t.status === \'VERIFIED\'){\n    actionHtml = `<span style="color:#2e7d32;font-weight:600">✅ This record has been verified.</span>\n      <button class="btn btn-edit" onclick="setEdit(\'${key}\',${idx},true)">✏️ Edit &amp; Correct</button>`;\n  } else if(isEdit){\n    actionHtml = `\n      <button class="btn btn-save" id="saveBtn_${idx}" onclick="saveUpdates(${idx})" disabled>\n        💾 Save Changes\n      </button>\n      <button class="btn btn-verify" onclick="verifyRecord(${idx})">✅ Verify as Correct</button>\n      <button class="btn btn-cancel" onclick="setEdit(\'${key}\',${idx},false)">✖ Cancel</button>\n      <span class="changes-count" id="chgCount_${idx}" style="display:none">0 changes</span>`;\n  } else {\n    actionHtml = `\n      <button class="btn btn-verify" onclick="verifyRecord(${idx})">✅ All data is correct — Verify</button>\n      <button class="btn btn-edit" onclick="setEdit(\'${key}\',${idx},true)">✏️ Edit / Correct Data</button>`;\n  }\n\n  const changesBadge = chCount>0 ? `<span style="font-size:.78rem;background:rgba(255,255,255,.2);padding:3px 10px;border-radius:12px;margin-left:8px">${chCount} edit(s)</span>` : \'\';\n\n  return `\n    <div class="teacher-card" id="card_${idx}">\n      <div class="teacher-card-header">\n        <div>\n          <div class="teacher-name">👤 ${escHtml(t.teacher_name)} ${changesBadge}</div>\n          <div class="teacher-meta">${pf} &nbsp;·&nbsp; S.No. ${t.sl_no||\'—\'}${ts}</div>\n        </div>\n        <div class="status-badge badge-${t.status||\'PENDING\'}">${t.status||\'PENDING\'}</div>\n      </div>\n      ${isEdit?`<div class="edit-mode-bar show">✏️ Edit mode active — modify the fields below then click <strong>Save Changes</strong> or <strong>Verify</strong>.</div>`:\'\'}\n      <div class="teacher-body" id="body_${idx}">${groupsHtml}</div>\n      <div class="action-bar">${actionHtml}</div>\n    </div>`;\n}\n\nfunction cardKey(t){ return t.teacher_name+\'||\'+t.proforma; }\n\n/* ── Edit mode toggle ── */\nfunction setEdit(key, idx, on){\n  editModes[key] = on;\n  // Re-render card in place\n  const card   = document.getElementById(`card_${idx}`);\n  const t      = allTeachers[idx];\n  card.outerHTML = buildCard(t, idx);\n}\n\n/* ── Track changes ── */\nfunction markChanged(idx, fk){\n  const t   = allTeachers[idx];\n  const inp = document.getElementById(`inp_${idx}_${fk}`);\n  const fi  = document.getElementById(`fi_${idx}_${fk}`);\n  if(!inp||!fi) return;\n  const changed = inp.value.trim() !== (t[fk]||\'\').trim();\n  fi.classList.toggle(\'changed\', changed);\n  updateChangeCount(idx);\n}\n\nfunction updateChangeCount(idx){\n  const t  = allTeachers[idx];\n  let cnt  = 0;\n  for(const fk of Object.keys(fieldLabels)){\n    const inp = document.getElementById(`inp_${idx}_${fk}`);\n    if(inp && inp.value.trim() !== (t[fk]||\'\').trim()) cnt++;\n  }\n  const cc = document.getElementById(`chgCount_${idx}`);\n  const sb = document.getElementById(`saveBtn_${idx}`);\n  if(cc){ cc.textContent=`${cnt} change(s)`; cc.style.display=cnt?\'inline-block\':\'none\'; }\n  if(sb) sb.disabled = (cnt===0);\n}\n\n/* ── Collect edits ── */\nfunction collectEdits(idx){\n  const t = allTeachers[idx];\n  const updated = {};\n  for(const fk of Object.keys(fieldLabels)){\n    const inp = document.getElementById(`inp_${idx}_${fk}`);\n    if(inp && inp.value.trim() !== (t[fk]||\'\').trim()){\n      updated[fk] = inp.value.trim();\n    }\n  }\n  return updated;\n}\n\n/* ── Save updates ── */\nasync function saveUpdates(idx){\n  const t       = allTeachers[idx];\n  const fields  = collectEdits(idx);\n  if(!Object.keys(fields).length){ showToast(\'No changes to save.\',\'info\'); return; }\n\n  const sb = document.getElementById(`saveBtn_${idx}`);\n  if(sb){ sb.disabled=true; sb.innerHTML=\'<div class="spinner"></div> Saving…\'; }\n\n  try{\n    const res  = await fetch(\'/api/teacher/update\',{\n      method:\'POST\',\n      headers:{\'Content-Type\':\'application/json\'},\n      body: JSON.stringify({teacher_name:t.teacher_name, proforma:t.proforma, fields})\n    });\n    const data = await res.json();\n    if(data.success){\n      // Apply changes locally\n      Object.assign(t, fields);\n      t.status = \'UPDATED\';\n      t.last_updated = data.timestamp || \'\';\n      editModes[cardKey(t)] = false;\n      const card = document.getElementById(`card_${idx}`);\n      card.outerHTML = buildCard(t, idx);\n      showToast(\'✅ \'+data.message, \'success\');\n    } else {\n      showToast(\'❌ \'+(data.error||\'Update failed.\'), \'error\');\n      if(sb){ sb.disabled=false; sb.innerHTML=\'💾 Save Changes\'; }\n    }\n  } catch(e){\n    showToast(\'❌ Network error. Please retry.\', \'error\');\n    if(sb){ sb.disabled=false; sb.innerHTML=\'💾 Save Changes\'; }\n  }\n}\n\n/* ── Verify record ── */\nasync function verifyRecord(idx){\n  const t = allTeachers[idx];\n  // Collect any pending edits first\n  const fields = collectEdits(idx);\n  if(Object.keys(fields).length){\n    // Save edits then verify\n    await saveUpdates(idx);\n    // re-read allTeachers[idx] after update\n  }\n\n  const vbtn = document.querySelector(`#card_${idx} .btn-verify`);\n  if(vbtn){ vbtn.disabled=true; vbtn.innerHTML=\'<div class="spinner"></div> Verifying…\'; }\n\n  try{\n    const res  = await fetch(\'/api/teacher/verify\',{\n      method:\'POST\',\n      headers:{\'Content-Type\':\'application/json\'},\n      body: JSON.stringify({teacher_name:t.teacher_name, proforma:t.proforma})\n    });\n    const data = await res.json();\n    if(data.success){\n      t.status = \'VERIFIED\';\n      t.last_updated = data.timestamp || \'\';\n      editModes[cardKey(t)] = false;\n      const card = document.getElementById(`card_${idx}`);\n      card.outerHTML = buildCard(t, idx);\n      showToast(\'✅ \'+data.message, \'success\');\n    } else {\n      showToast(\'❌ \'+(data.error||\'Verification failed.\'), \'error\');\n    }\n  } catch(e){\n    showToast(\'❌ Network error. Please retry.\', \'error\');\n  }\n}\n\n/* ── Toast ── */\nlet toastTimer;\nfunction showToast(msg, type=\'success\'){\n  const el = document.getElementById(\'toast\');\n  el.textContent = msg;\n  el.className = `toast ${type} show`;\n  clearTimeout(toastTimer);\n  toastTimer = setTimeout(()=>{ el.className=\'toast\'; }, 4500);\n}\n\n/* ── Escape HTML ── */\nfunction escHtml(s){\n  if(s==null) return \'\';\n  return String(s).replace(/&/g,\'&amp;\').replace(/</g,\'&lt;\').replace(/>/g,\'&gt;\').replace(/"/g,\'&quot;\');\n}\n</script>\n</body>\n</html>\n'

ADMIN_LOGIN_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>Admin Login — Chikiti Block</title>\n<style>\n  :root{--navy:#0d2366;--steel:#1f4e79;--red:#c62828}\n  *{box-sizing:border-box;margin:0;padding:0}\n  body{font-family:\'Segoe UI\',Arial,sans-serif;background:linear-gradient(135deg,#1a1a3e 0%,#0d2366 50%,#1f4e79 100%);min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:24px}\n  .back-link{position:fixed;top:16px;left:16px;color:rgba(255,255,255,.8);text-decoration:none;font-size:.88rem;font-weight:600;background:rgba(255,255,255,.12);padding:8px 14px;border-radius:8px;border:1px solid rgba(255,255,255,.2)}\n  .back-link:hover{background:rgba(255,255,255,.2)}\n  .card{background:#fff;border-radius:18px;box-shadow:0 16px 60px rgba(0,0,0,.35);padding:44px 40px 40px;max-width:440px;width:100%}\n  .logo{text-align:center;margin-bottom:28px}\n  .logo .icon{font-size:3rem;margin-bottom:10px}\n  .logo h1{font-size:1.45rem;color:var(--navy);font-weight:700}\n  .logo p{font-size:.84rem;color:#666;margin-top:4px}\n  .badge{display:inline-block;background:#0d2366;color:#fff;font-size:.7rem;padding:3px 10px;border-radius:12px;margin-top:6px;letter-spacing:.5px}\n  .field{margin-bottom:18px}\n  label{display:block;font-size:.87rem;font-weight:600;color:var(--steel);margin-bottom:6px}\n  input[type=text],input[type=password]{\n    width:100%;padding:11px 14px;border:2px solid #d0daf0;border-radius:9px;\n    font-size:.95rem;color:#222;outline:none;transition:border-color .2s;background:#fdfdff}\n  input:focus{border-color:var(--navy)}\n  .pw-wrap{position:relative}\n  .pw-toggle{position:absolute;right:12px;top:50%;transform:translateY(-50%);cursor:pointer;font-size:1.1rem;user-select:none}\n  .btn-login{width:100%;padding:13px;background:linear-gradient(135deg,#1a1a3e,var(--navy));color:#fff;border:none;border-radius:10px;font-size:1rem;font-weight:700;cursor:pointer;transition:opacity .2s;margin-top:6px}\n  .btn-login:hover{opacity:.88}\n  .btn-login:disabled{opacity:.6;cursor:not-allowed}\n  .alert{padding:11px 15px;border-radius:8px;font-size:.87rem;margin-bottom:14px;display:none}\n  .alert.error{background:#ffeaea;color:var(--red);border:1px solid #ffcdd2;display:block}\n  .spinner{display:none;width:18px;height:18px;border:3px solid rgba(255,255,255,.4);border-top-color:#fff;border-radius:50%;animation:spin .7s linear infinite;margin:auto}\n  @keyframes spin{to{transform:rotate(360deg)}}\n  .secure-note{text-align:center;margin-top:18px;font-size:.77rem;color:#999}\n</style>\n</head>\n<body>\n\n<a class="back-link" href="/">← Home</a>\n\n<div class="card">\n  <div class="logo">\n    <div class="icon">🛡️</div>\n    <h1>Admin Login</h1>\n    <p>Teacher Verification System</p>\n    <span class="badge">ADMINISTRATOR ACCESS</span>\n  </div>\n\n  <div class="alert error" id="alertBox" style="display:none"></div>\n\n  <div class="field">\n    <label for="username">👤 Username</label>\n    <input type="text" id="username" placeholder="Enter admin username" autocomplete="username">\n  </div>\n\n  <div class="field">\n    <label for="password">🔑 Password</label>\n    <div class="pw-wrap">\n      <input type="password" id="password" placeholder="Enter password" autocomplete="current-password">\n      <span class="pw-toggle" onclick="togglePw()">👁</span>\n    </div>\n  </div>\n\n  <button class="btn-login" id="loginBtn" onclick="doLogin()">\n    <span id="btnText">Login to Admin Panel →</span>\n    <div class="spinner" id="spinner"></div>\n  </button>\n\n  <p class="secure-note">🔒 Access restricted to authorised administrators only</p>\n</div>\n\n<script>\nfunction togglePw(){\n  const pw = document.getElementById(\'password\');\n  pw.type = pw.type===\'password\' ? \'text\' : \'password\';\n}\n\nasync function doLogin(){\n  const username = document.getElementById(\'username\').value.trim();\n  const password = document.getElementById(\'password\').value.trim();\n  const alertBox = document.getElementById(\'alertBox\');\n  alertBox.style.display = \'none\';\n\n  if(!username || !password){ showErr(\'Please enter username and password.\'); return; }\n\n  setBusy(true);\n  try{\n    const res  = await fetch(\'/admin/login\',{\n      method:\'POST\',\n      headers:{\'Content-Type\':\'application/json\'},\n      body: JSON.stringify({username, password})\n    });\n    const data = await res.json();\n    if(data.success){\n      window.location.href = \'/admin/dashboard\';\n    } else {\n      showErr(data.error || \'Invalid credentials.\');\n    }\n  } catch(e){ showErr(\'Network error. Please try again.\'); }\n  finally{ setBusy(false); }\n}\n\nfunction showErr(msg){\n  const a = document.getElementById(\'alertBox\');\n  a.textContent = msg; a.style.display=\'block\';\n}\nfunction setBusy(on){\n  document.getElementById(\'loginBtn\').disabled = on;\n  document.getElementById(\'btnText\').style.display = on?\'none\':\'inline\';\n  document.getElementById(\'spinner\').style.display = on?\'block\':\'none\';\n}\ndocument.addEventListener(\'keydown\', e=>{ if(e.key===\'Enter\') doLogin(); });\n</script>\n</body>\n</html>\n'

ADMIN_DASHBOARD_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>Admin Dashboard — Teacher Verification</title>\n<style>\n  :root{--navy:#0d2366;--steel:#1f4e79;--sky:#dce6f1;--green:#2e7d32;--amber:#e65100;--red:#c62828;--grey:#f5f7fa}\n  *{box-sizing:border-box;margin:0;padding:0}\n  body{font-family:\'Segoe UI\',Arial,sans-serif;background:var(--grey);min-height:100vh}\n\n  /* ── Top bar ── */\n  .topbar{background:linear-gradient(135deg,#1a1a3e,var(--navy));color:#fff;padding:14px 24px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;position:sticky;top:0;z-index:100;box-shadow:0 3px 12px rgba(0,0,0,.3)}\n  .topbar-left{display:flex;align-items:center;gap:12px}\n  .topbar-left .icon{font-size:1.7rem}\n  .topbar-left h1{font-size:1.1rem;font-weight:700}\n  .topbar-left p{font-size:.77rem;opacity:.75}\n  .topbar-right{display:flex;gap:8px;align-items:center;flex-wrap:wrap}\n  .admin-badge{background:rgba(255,255,255,.15);padding:6px 14px;border-radius:20px;font-size:.8rem}\n  .topbar-btn{background:rgba(255,255,255,.12);color:#fff;border:1px solid rgba(255,255,255,.25);padding:8px 14px;border-radius:8px;cursor:pointer;font-size:.82rem;text-decoration:none;transition:background .2s;display:flex;align-items:center;gap:5px}\n  .topbar-btn:hover{background:rgba(255,255,255,.25)}\n  .topbar-btn.success-bg{background:linear-gradient(135deg,#1b5e20,#2e7d32);border:none}\n\n  /* ── Container ── */\n  .container{max-width:1200px;margin:0 auto;padding:24px 18px 60px}\n\n  /* ── Stat cards ── */\n  .stats-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:16px;margin-bottom:28px}\n  .stat-card{background:#fff;border-radius:13px;box-shadow:0 2px 12px rgba(0,0,0,.07);padding:20px 18px;border-top:4px solid var(--navy);text-align:center}\n  .stat-card.green{border-color:#43a047}\n  .stat-card.blue{border-color:#1e88e5}\n  .stat-card.orange{border-color:#fb8c00}\n  .stat-card.purple{border-color:#8e24aa}\n  .stat-number{font-size:2.2rem;font-weight:800;color:var(--navy);line-height:1}\n  .stat-label{font-size:.8rem;color:#777;margin-top:6px;font-weight:600;text-transform:uppercase;letter-spacing:.4px}\n\n  /* ── Section panel ── */\n  .panel{background:#fff;border-radius:14px;box-shadow:0 2px 14px rgba(0,0,0,.07);margin-bottom:26px;overflow:hidden}\n  .panel-header{background:linear-gradient(135deg,var(--navy),var(--steel));color:#fff;padding:14px 20px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px}\n  .panel-header h2{font-size:1rem;font-weight:700;display:flex;align-items:center;gap:8px}\n  .panel-body{padding:20px}\n\n  /* ── Filters bar ── */\n  .filters-bar{display:flex;gap:10px;flex-wrap:wrap;align-items:center;margin-bottom:16px}\n  .filters-bar select,.filters-bar input{\n    padding:8px 12px;border:1.5px solid #d0daf0;border-radius:8px;font-size:.85rem;outline:none;color:#222;background:#fff}\n  .filters-bar select:focus,.filters-bar input:focus{border-color:var(--navy)}\n  .filters-bar input{min-width:200px}\n  .btn-sm{padding:8px 16px;border-radius:8px;font-size:.83rem;font-weight:600;border:none;cursor:pointer;transition:all .2s;display:inline-flex;align-items:center;gap:5px}\n  .btn-primary{background:var(--navy);color:#fff}\n  .btn-primary:hover{opacity:.88}\n  .btn-success{background:#2e7d32;color:#fff}\n  .btn-success:hover{opacity:.88}\n  .btn-danger{background:#c62828;color:#fff}\n  .btn-danger:hover{opacity:.88}\n  .btn-secondary{background:#455a64;color:#fff}\n  .btn-secondary:hover{opacity:.88}\n\n  /* ── Teacher table ── */\n  .table-wrap{overflow-x:auto}\n  table{width:100%;border-collapse:collapse;font-size:.83rem}\n  thead tr{background:var(--navy);color:#fff}\n  thead th{padding:10px 12px;text-align:left;font-weight:600;white-space:nowrap}\n  tbody tr{border-bottom:1px solid #f0f2f8;transition:background .15s}\n  tbody tr:hover{background:#f0f4ff}\n  tbody td{padding:9px 12px;vertical-align:middle}\n  .badge{display:inline-block;padding:4px 10px;border-radius:12px;font-size:.73rem;font-weight:700;text-transform:uppercase}\n  .badge-PENDING{background:#fff3e0;color:#e65100;border:1px solid #ffcc80}\n  .badge-VERIFIED{background:#e8f5e9;color:#1b5e20;border:1px solid #81c784}\n  .badge-UPDATED{background:#e3f2fd;color:#0d47a1;border:1px solid #64b5f6}\n  .teacher-name-cell{font-weight:600;color:var(--navy)}\n  .action-btns{display:flex;gap:6px;flex-wrap:nowrap}\n\n  /* ── Proforma tabs ── */\n  .tab-bar{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:16px}\n  .tab-btn{padding:7px 16px;border-radius:20px;font-size:.82rem;font-weight:600;border:2px solid #d0daf0;background:#fff;cursor:pointer;transition:all .2s;color:#555}\n  .tab-btn.active{background:var(--navy);color:#fff;border-color:var(--navy)}\n\n  /* ── Progress bars in proforma ── */\n  .pf-progress{margin-bottom:4px}\n  .mini-bar{height:6px;background:#e0e0e0;border-radius:3px;overflow:hidden;margin-top:3px}\n  .mini-fill{height:100%;border-radius:3px;background:linear-gradient(90deg,#43a047,#1b5e20)}\n\n  /* ── Modal ── */\n  .modal-bg{position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:5000;display:none;align-items:center;justify-content:center;padding:16px}\n  .modal-bg.open{display:flex}\n  .modal{background:#fff;border-radius:16px;max-width:820px;width:100%;max-height:90vh;display:flex;flex-direction:column;box-shadow:0 20px 60px rgba(0,0,0,.35)}\n  .modal-header{background:linear-gradient(135deg,var(--navy),var(--steel));color:#fff;padding:16px 22px;border-radius:16px 16px 0 0;display:flex;justify-content:space-between;align-items:center}\n  .modal-header h3{font-size:1rem;font-weight:700}\n  .modal-close{background:none;border:none;color:#fff;font-size:1.4rem;cursor:pointer;line-height:1}\n  .modal-body{padding:20px;overflow-y:auto;flex:1}\n  .modal-footer{padding:14px 20px;border-top:1px solid #eee;display:flex;gap:10px;justify-content:flex-end;flex-wrap:wrap}\n  .modal-fields-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:10px;margin-bottom:14px}\n  .mfield{border:1.5px solid #e8edf5;border-radius:8px;padding:9px 12px}\n  .mfield-label{font-size:.72rem;color:#888;font-weight:600;text-transform:uppercase;margin-bottom:3px}\n  .mfield-input{width:100%;border:none;background:transparent;font-size:.9rem;color:#1a237e;outline:none;font-family:inherit}\n  .section-title{font-size:.88rem;font-weight:700;color:var(--steel);margin:14px 0 8px;padding-bottom:5px;border-bottom:2px solid var(--sky)}\n\n  /* ── Export panel ── */\n  .export-row{display:flex;gap:10px;flex-wrap:wrap;align-items:center}\n  .export-row select{padding:8px 12px;border:1.5px solid #d0daf0;border-radius:8px;font-size:.85rem;outline:none}\n\n  /* ── Activity log ── */\n  .log-table{font-size:.8rem}\n  .log-table thead tr{background:#37474f}\n\n  /* ── Loading ── */\n  #loadingOverlay{position:fixed;inset:0;background:rgba(255,255,255,.88);display:flex;align-items:center;justify-content:center;z-index:9000;flex-direction:column;gap:14px}\n  #loadingOverlay .sp{width:44px;height:44px;border:5px solid var(--sky);border-top-color:var(--navy);border-radius:50%;animation:spin 1s linear infinite}\n  #loadingOverlay p{color:var(--navy);font-weight:600}\n  @keyframes spin{to{transform:rotate(360deg)}}\n\n  /* ── Toast ── */\n  .toast{position:fixed;bottom:24px;right:24px;padding:13px 20px;border-radius:10px;color:#fff;font-size:.88rem;font-weight:600;z-index:9999;opacity:0;transform:translateY(18px);transition:all .3s;pointer-events:none;max-width:360px;box-shadow:0 6px 24px rgba(0,0,0,.2)}\n  .toast.show{opacity:1;transform:translateY(0)}\n  .toast.success{background:#2e7d32}\n  .toast.error{background:#c62828}\n  .toast.info{background:var(--navy)}\n\n  /* ── Pagination ── */\n  .pagination{display:flex;gap:6px;justify-content:flex-end;align-items:center;margin-top:14px;flex-wrap:wrap}\n  .page-info{font-size:.82rem;color:#666;margin-right:8px}\n  .page-btn{width:32px;height:32px;border:1.5px solid #d0daf0;background:#fff;border-radius:6px;cursor:pointer;font-size:.82rem;transition:all .2s;display:flex;align-items:center;justify-content:center}\n  .page-btn.active{background:var(--navy);color:#fff;border-color:var(--navy)}\n  .page-btn:hover:not(.active){background:var(--sky)}\n\n  @media(max-width:700px){\n    .stats-grid{grid-template-columns:1fr 1fr}\n    .modal-fields-grid{grid-template-columns:1fr}\n    .topbar{flex-direction:column;align-items:flex-start}\n  }\n</style>\n</head>\n<body>\n\n<!-- Loading -->\n<div id="loadingOverlay">\n  <div class="sp"></div>\n  <p>Loading admin dashboard…</p>\n</div>\n\n<!-- Top Bar -->\n<div class="topbar">\n  <div class="topbar-left">\n    <div class="icon">🛡️</div>\n    <div>\n      <h1>Admin Dashboard</h1>\n      <p>Teacher Proforma Verification — Chikiti Block, 2026</p>\n    </div>\n  </div>\n  <div class="topbar-right">\n    <div class="admin-badge">👤 {{ admin_user }}</div>\n    <button class="topbar-btn" onclick="refreshAll()">🔄 Refresh</button>\n    <button class="topbar-btn success-bg" onclick="exportExcel(\'all\',\'\',\'\')">📥 Export Excel</button>\n    <a href="/admin/logout" class="topbar-btn">🚪 Logout</a>\n  </div>\n</div>\n\n<!-- Container -->\n<div class="container">\n\n  <!-- Stat Cards -->\n  <div class="stats-grid" id="statsGrid">\n    <div class="stat-card"><div class="stat-number" id="stTotal">—</div><div class="stat-label">Total Teachers</div></div>\n    <div class="stat-card green"><div class="stat-number" id="stVerified">—</div><div class="stat-label">✅ Verified</div></div>\n    <div class="stat-card blue"><div class="stat-number" id="stUpdated">—</div><div class="stat-label">✏️ Updated</div></div>\n    <div class="stat-card orange"><div class="stat-number" id="stPending">—</div><div class="stat-label">⏳ Pending</div></div>\n    <div class="stat-card purple"><div class="stat-number" id="stPct">—</div><div class="stat-label">% Completed</div></div>\n  </div>\n\n  <!-- Proforma Summary -->\n  <div class="panel" id="pfPanel">\n    <div class="panel-header">\n      <h2>📊 Proforma-wise Summary</h2>\n    </div>\n    <div class="panel-body" id="pfSummary" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:14px"></div>\n  </div>\n\n  <!-- Teachers Table -->\n  <div class="panel">\n    <div class="panel-header">\n      <h2>👨\u200d🏫 Teacher Records</h2>\n      <div style="display:flex;gap:8px;flex-wrap:wrap">\n        <button class="btn-sm btn-success" onclick="exportExcel(\'all\',\'\',\'\')">📥 Export All</button>\n        <button class="btn-sm btn-secondary" onclick="showExportModal()">⚙️ Custom Export</button>\n      </div>\n    </div>\n    <div class="panel-body">\n      <!-- Filters -->\n      <div class="filters-bar">\n        <input type="text" id="searchInput" placeholder="🔍 Search name or school…" oninput="applyFilters()">\n        <select id="filterProforma" onchange="applyFilters()">\n          <option value="">All Proformas</option>\n          <option>PROFORMA I</option><option>PROFORMA II</option><option>PROFORMA III</option>\n          <option>PROFORMA IV</option><option>PROFORMA V</option><option>PROFORMA VI</option><option>PROFORMA VII</option>\n        </select>\n        <select id="filterStatus" onchange="applyFilters()">\n          <option value="">All Status</option>\n          <option>PENDING</option><option>VERIFIED</option><option>UPDATED</option>\n        </select>\n        <select id="filterSchool" onchange="applyFilters()">\n          <option value="">All Schools</option>\n        </select>\n        <button class="btn-sm btn-primary" onclick="clearFilters()">✖ Clear</button>\n      </div>\n\n      <div id="teacherCount" style="font-size:.82rem;color:#666;margin-bottom:10px"></div>\n\n      <div class="table-wrap">\n        <table id="teacherTable">\n          <thead><tr>\n            <th>#</th><th>Name</th><th>Proforma</th><th>School</th>\n            <th>Status</th><th>Last Updated</th><th>Changes</th><th>Actions</th>\n          </tr></thead>\n          <tbody id="teacherTbody"></tbody>\n        </table>\n      </div>\n      <div class="pagination" id="pagination"></div>\n    </div>\n  </div>\n\n  <!-- Export Panel -->\n  <div class="panel" id="exportPanel">\n    <div class="panel-header"><h2>📥 Export Data to Excel</h2></div>\n    <div class="panel-body">\n      <div class="export-row">\n        <select id="expType" onchange="updateExpFilter()">\n          <option value="all">All Records</option>\n          <option value="proforma">By Proforma</option>\n          <option value="school">By School</option>\n        </select>\n        <select id="expFilter" style="display:none">\n          <option value="">— Select —</option>\n        </select>\n        <select id="expStatus">\n          <option value="">All Status</option>\n          <option value="VERIFIED">Verified Only</option>\n          <option value="UPDATED">Updated Only</option>\n          <option value="PENDING">Pending Only</option>\n        </select>\n        <button class="btn-sm btn-success" onclick="downloadExport()">📥 Download Excel</button>\n      </div>\n      <p style="font-size:.78rem;color:#888;margin-top:10px">💡 Excel will be colour-coded: Green = Verified, Amber = Updated, White = Pending. Includes all proforma sheets + summary tab.</p>\n    </div>\n  </div>\n\n  <!-- Activity Log -->\n  <div class="panel">\n    <div class="panel-header">\n      <h2>📋 Activity Log</h2>\n      <button class="topbar-btn" onclick="loadLogs()">🔄 Refresh</button>\n    </div>\n    <div class="panel-body">\n      <div class="table-wrap">\n        <table class="log-table">\n          <thead><tr>\n            <th>Time</th><th>Action</th><th>Teacher</th><th>Proforma</th><th>School</th><th>Details</th>\n          </tr></thead>\n          <tbody id="logTbody"><tr><td colspan="6" style="text-align:center;color:#aaa;padding:16px">Loading…</td></tr></tbody>\n        </table>\n      </div>\n    </div>\n  </div>\n\n</div><!-- /container -->\n\n<!-- Toast -->\n<div class="toast" id="toast"></div>\n\n<!-- ──────────── Teacher Detail / Edit Modal ──────────── -->\n<div class="modal-bg" id="teacherModal">\n  <div class="modal">\n    <div class="modal-header">\n      <h3 id="modalTitle">Teacher Details</h3>\n      <button class="modal-close" onclick="closeModal()">✕</button>\n    </div>\n    <div class="modal-body" id="modalBody"></div>\n    <div class="modal-footer">\n      <button class="btn-sm btn-success" onclick="modalVerify()">✅ Set Verified</button>\n      <button class="btn-sm btn-primary" onclick="modalSave()">💾 Save Changes</button>\n      <button class="btn-sm btn-danger" onclick="modalReset()">↩ Reset to Pending</button>\n      <button class="btn-sm" style="background:#90a4ae;color:#fff" onclick="closeModal()">Close</button>\n    </div>\n  </div>\n</div>\n\n<!-- ──────────── Custom Export Modal ──────────── -->\n<div class="modal-bg" id="exportModal">\n  <div class="modal" style="max-width:500px">\n    <div class="modal-header">\n      <h3>Custom Export Options</h3>\n      <button class="modal-close" onclick="document.getElementById(\'exportModal\').classList.remove(\'open\')">✕</button>\n    </div>\n    <div class="modal-body">\n      <div class="field-group" style="margin-bottom:14px">\n        <label style="font-size:.85rem;font-weight:600;color:var(--steel);display:block;margin-bottom:6px">Export Type</label>\n        <select id="expType2" onchange="updateExpFilter2()" style="width:100%;padding:9px 12px;border:1.5px solid #d0daf0;border-radius:8px;font-size:.88rem">\n          <option value="all">All Records</option>\n          <option value="proforma">By Proforma</option>\n          <option value="school">By School</option>\n        </select>\n      </div>\n      <div class="field-group" id="expFilterGroup2" style="display:none;margin-bottom:14px">\n        <label style="font-size:.85rem;font-weight:600;color:var(--steel);display:block;margin-bottom:6px">Filter Value</label>\n        <select id="expFilter2" style="width:100%;padding:9px 12px;border:1.5px solid #d0daf0;border-radius:8px;font-size:.88rem">\n          <option value="">— Select —</option>\n        </select>\n      </div>\n      <div class="field-group">\n        <label style="font-size:.85rem;font-weight:600;color:var(--steel);display:block;margin-bottom:6px">Status Filter</label>\n        <select id="expStatus2" style="width:100%;padding:9px 12px;border:1.5px solid #d0daf0;border-radius:8px;font-size:.88rem">\n          <option value="">All Status</option>\n          <option value="VERIFIED">Verified Only</option>\n          <option value="UPDATED">Updated Only</option>\n          <option value="PENDING">Pending Only</option>\n        </select>\n      </div>\n    </div>\n    <div class="modal-footer">\n      <button class="btn-sm btn-success" onclick="downloadExport2()">📥 Download Excel</button>\n      <button class="btn-sm" style="background:#90a4ae;color:#fff" onclick="document.getElementById(\'exportModal\').classList.remove(\'open\')">Cancel</button>\n    </div>\n  </div>\n</div>\n\n<script>\n/* ── State ── */\nlet allTeachers = [], fieldLabels = {}, fieldGroups = [];\nlet filteredTeachers = [];\nlet currentPage = 1;\nconst PAGE_SIZE = 15;\nlet currentModalTeacher = null;\nlet allSchools = [];\n\n/* ── Boot ── */\nwindow.onload = async () => {\n  await Promise.all([loadStats(), loadTeachers(), loadLogs()]);\n  document.getElementById(\'loadingOverlay\').style.display = \'none\';\n};\n\nasync function refreshAll(){\n  document.getElementById(\'loadingOverlay\').style.display = \'flex\';\n  await Promise.all([loadStats(), loadTeachers(), loadLogs()]);\n  document.getElementById(\'loadingOverlay\').style.display = \'none\';\n  showToast(\'Dashboard refreshed.\', \'success\');\n}\n\n/* ── Stats ── */\nasync function loadStats(){\n  const res  = await fetch(\'/api/admin/stats\');\n  const data = await res.json();\n  document.getElementById(\'stTotal\').textContent    = data.total;\n  document.getElementById(\'stVerified\').textContent  = data.verified;\n  document.getElementById(\'stUpdated\').textContent   = data.updated;\n  document.getElementById(\'stPending\').textContent   = data.pending;\n  const pct = data.total ? Math.round((data.verified+data.updated)/data.total*100) : 0;\n  document.getElementById(\'stPct\').textContent = pct+\'%\';\n\n  // Proforma summary\n  const pfDiv = document.getElementById(\'pfSummary\');\n  pfDiv.innerHTML = \'\';\n  for(const [pf, s] of Object.entries(data.proforma_stats||{})){\n    const donePct = s.total ? Math.round((s.verified+s.updated)/s.total*100) : 0;\n    pfDiv.insertAdjacentHTML(\'beforeend\',`\n      <div style="background:#f8faff;border:1.5px solid #e8edf5;border-radius:10px;padding:14px">\n        <div style="font-weight:700;color:var(--navy);font-size:.9rem;margin-bottom:8px">${pf}</div>\n        <div style="font-size:.78rem;color:#555">Total: <strong>${s.total}</strong> | ✅ ${s.verified} | ✏️ ${s.updated} | ⏳ ${s.pending}</div>\n        <div class="mini-bar" style="margin-top:8px"><div class="mini-fill" style="width:${donePct}%"></div></div>\n        <div style="font-size:.74rem;color:#888;margin-top:4px;text-align:right">${donePct}% done</div>\n      </div>`);\n  }\n\n  // Populate school filter\n  allSchools = Object.keys(data.school_stats||{}).sort();\n  const sch = document.getElementById(\'filterSchool\');\n  sch.innerHTML = \'<option value="">All Schools</option>\';\n  allSchools.forEach(s=>{ sch.insertAdjacentHTML(\'beforeend\',`<option>${s}</option>`); });\n}\n\n/* ── Teachers list ── */\nasync function loadTeachers(){\n  const res  = await fetch(\'/api/admin/teachers\');\n  const data = await res.json();\n  allTeachers = data.teachers || [];\n  fieldLabels = data.field_labels || {};\n  filteredTeachers = [...allTeachers];\n  currentPage = 1;\n  renderTable();\n}\n\nfunction applyFilters(){\n  const search = document.getElementById(\'searchInput\').value.toUpperCase();\n  const pf     = document.getElementById(\'filterProforma\').value;\n  const status = document.getElementById(\'filterStatus\').value;\n  const school = document.getElementById(\'filterSchool\').value;\n  filteredTeachers = allTeachers.filter(t=>{\n    if(pf     && t.proforma !== pf) return false;\n    if(status && (t.status||\'PENDING\') !== status) return false;\n    if(school && (t.school||\'\').trim() !== school) return false;\n    if(search && !((t.teacher_name||\'\').toUpperCase().includes(search) ||\n                   (t.school||\'\').toUpperCase().includes(search))) return false;\n    return true;\n  });\n  currentPage = 1;\n  renderTable();\n}\n\nfunction clearFilters(){\n  document.getElementById(\'searchInput\').value=\'\';\n  document.getElementById(\'filterProforma\').value=\'\';\n  document.getElementById(\'filterStatus\').value=\'\';\n  document.getElementById(\'filterSchool\').value=\'\';\n  applyFilters();\n}\n\nfunction renderTable(){\n  const start = (currentPage-1)*PAGE_SIZE;\n  const slice = filteredTeachers.slice(start, start+PAGE_SIZE);\n  const tbody = document.getElementById(\'teacherTbody\');\n  document.getElementById(\'teacherCount\').textContent = \n    `Showing ${Math.min(start+1,filteredTeachers.length)}–${Math.min(start+slice.length,filteredTeachers.length)} of ${filteredTeachers.length} records`;\n\n  if(!slice.length){\n    tbody.innerHTML = \'<tr><td colspan="8" style="text-align:center;color:#aaa;padding:20px">No records found.</td></tr>\';\n    document.getElementById(\'pagination\').innerHTML=\'\';\n    return;\n  }\n  tbody.innerHTML = slice.map((t,i)=>{\n    const idx    = start+i;\n    const chCnt  = (t.change_history||[]).length;\n    const status = t.status||\'PENDING\';\n    return `<tr>\n      <td style="color:#999">${idx+1}</td>\n      <td class="teacher-name-cell">${esc(t.teacher_name)}</td>\n      <td style="font-size:.78rem;color:#555">${t.proforma||\'\'}</td>\n      <td style="font-size:.8rem">${esc(t.school||\'\')}</td>\n      <td><span class="badge badge-${status}">${status}</span></td>\n      <td style="font-size:.78rem;color:#777">${t.last_updated||\'—\'}</td>\n      <td style="text-align:center">${chCnt>0?`<span style="background:#e3f2fd;color:#1565c0;padding:3px 8px;border-radius:10px;font-size:.75rem">${chCnt} edit(s)</span>`:\'—\'}</td>\n      <td>\n        <div class="action-btns">\n          <button class="btn-sm btn-primary" style="padding:5px 10px;font-size:.75rem" onclick="openTeacher(\'${esc(t.teacher_name)}\',\'${esc(t.proforma)}\')">✏️ Edit</button>\n          <button class="btn-sm btn-danger" style="padding:5px 10px;font-size:.75rem" onclick="resetTeacher(\'${esc(t.teacher_name)}\',\'${esc(t.proforma)}\')">↩ Reset</button>\n        </div>\n      </td>\n    </tr>`;\n  }).join(\'\');\n\n  // Pagination\n  const total = Math.ceil(filteredTeachers.length/PAGE_SIZE);\n  const pg = document.getElementById(\'pagination\');\n  if(total<=1){ pg.innerHTML=\'\'; return; }\n  let html = `<span class="page-info">Page ${currentPage} of ${total}</span>`;\n  if(currentPage>1) html+=`<button class="page-btn" onclick="goPage(${currentPage-1})">‹</button>`;\n  const start_p = Math.max(1,currentPage-2), end_p = Math.min(total,currentPage+2);\n  for(let p=start_p;p<=end_p;p++) html+=`<button class="page-btn${p===currentPage?\' active\':\'\'}" onclick="goPage(${p})">${p}</button>`;\n  if(currentPage<total) html+=`<button class="page-btn" onclick="goPage(${currentPage+1})">›</button>`;\n  pg.innerHTML = html;\n}\n\nfunction goPage(p){ currentPage=p; renderTable(); window.scrollTo({top:400,behavior:\'smooth\'}); }\n\n/* ── Teacher Modal ── */\nasync function openTeacher(name, proforma){\n  currentModalTeacher = null;\n  const res  = await fetch(`/api/admin/teacher/${encodeURIComponent(name)}/${encodeURIComponent(proforma)}`);\n  const data = await res.json();\n  if(!data.teacher){ showToast(\'Record not found.\',\'error\'); return; }\n  const t = data.teacher;\n  currentModalTeacher = t;\n\n  document.getElementById(\'modalTitle\').textContent = `✏️ ${t.teacher_name} — ${t.proforma}`;\n  let html = `<div style="display:flex;gap:10px;align-items:center;margin-bottom:14px;flex-wrap:wrap">\n    <span class="badge badge-${t.status||\'PENDING\'}">${t.status||\'PENDING\'}</span>\n    ${t.last_updated?`<span style="font-size:.78rem;color:#888">Last updated: ${t.last_updated} by ${t.updated_by||\'—\'}</span>`:\'\'}\n  </div>`;\n\n  for(const grp of (data.field_groups||[])){\n    html += `<div class="section-title">${grp.title}</div><div class="modal-fields-grid">`;\n    for(const fk of grp.fields){\n      if(fk===\'sl_no\') continue;\n      const label = (data.field_labels||{})[fk]||fk;\n      const val   = t[fk]||\'\';\n      const readOnly = fk===\'teacher_name\' ? \'readonly style="color:#999"\' : \'\';\n      html += `<div class="mfield">\n        <div class="mfield-label">${label}</div>\n        <input class="mfield-input" id="mf_${fk}" value="${esc(val)}" ${readOnly}>\n      </div>`;\n    }\n    html += \'</div>\';\n  }\n\n  // Change history\n  const hist = t.change_history||[];\n  if(hist.length){\n    html += `<div class="section-title">📜 Change History (${hist.length} entries)</div>`;\n    html += hist.slice().reverse().map(h=>`\n      <div style="background:#f8f9ff;border:1px solid #e8edf5;border-radius:8px;padding:10px 12px;margin-bottom:8px;font-size:.8rem">\n        <div style="font-weight:600;color:var(--navy)">${h.timestamp} — by ${h.updated_by||\'unknown\'}</div>\n        ${Object.entries(h.changes||{}).map(([k,v])=>\n          typeof v === \'object\' && v.old !== undefined\n            ? `<div style="color:#555;margin-top:3px">• ${v.label||k}: <span style="color:#c62828;text-decoration:line-through">${v.old||\'—\'}</span> → <span style="color:#2e7d32">${v.new||\'—\'}</span></div>`\n            : `<div style="color:#555;margin-top:3px">• ${v.label||k}</div>`\n        ).join(\'\')}\n      </div>`).join(\'\');\n  }\n\n  document.getElementById(\'modalBody\').innerHTML = html;\n  document.getElementById(\'teacherModal\').classList.add(\'open\');\n}\n\nfunction closeModal(){\n  document.getElementById(\'teacherModal\').classList.remove(\'open\');\n  currentModalTeacher = null;\n}\n\nfunction collectModalFields(){\n  if(!currentModalTeacher) return {};\n  const fields = {};\n  const t = currentModalTeacher;\n  for(const grp of fieldGroups){\n    for(const fk of grp.fields){\n      if(fk===\'sl_no\'||fk===\'teacher_name\') continue;\n      const inp = document.getElementById(`mf_${fk}`);\n      if(inp && inp.value.trim() !== (t[fk]||\'\').trim()){\n        fields[fk] = inp.value.trim();\n      }\n    }\n  }\n  return fields;\n}\n\nasync function modalSave(){\n  if(!currentModalTeacher) return;\n  const fields = collectModalFields();\n  if(!Object.keys(fields).length){ showToast(\'No changes detected.\',\'info\'); return; }\n  const t   = currentModalTeacher;\n  const res = await fetch(\'/api/admin/teacher/update\',{\n    method:\'POST\', headers:{\'Content-Type\':\'application/json\'},\n    body: JSON.stringify({teacher_name:t.teacher_name, proforma:t.proforma, fields})\n  });\n  const data = await res.json();\n  if(data.success){ showToast(\'✅ Record updated.\',\'success\'); closeModal(); await loadTeachers(); await loadStats(); }\n  else showToast(\'❌ \'+(data.error||\'Update failed.\'),\'error\');\n}\n\nasync function modalVerify(){\n  if(!currentModalTeacher) return;\n  const t   = currentModalTeacher;\n  const res = await fetch(\'/api/admin/teacher/update\',{\n    method:\'POST\', headers:{\'Content-Type\':\'application/json\'},\n    body: JSON.stringify({teacher_name:t.teacher_name, proforma:t.proforma, fields:{}, status:\'VERIFIED\'})\n  });\n  const data = await res.json();\n  if(data.success){ showToast(\'✅ Status set to VERIFIED.\',\'success\'); closeModal(); await loadTeachers(); await loadStats(); }\n  else showToast(\'❌ \'+(data.error||\'Failed.\'),\'error\');\n}\n\nasync function modalReset(){\n  if(!currentModalTeacher) return;\n  if(!confirm(\'Reset this teacher to PENDING? Change history will be cleared.\')) return;\n  const t = currentModalTeacher;\n  await resetTeacher(t.teacher_name, t.proforma);\n  closeModal();\n}\n\n/* ── Reset teacher ── */\nasync function resetTeacher(name, proforma){\n  if(!confirm(`Reset "${name}" to PENDING?`)) return;\n  const res  = await fetch(\'/api/admin/teacher/reset\',{\n    method:\'POST\', headers:{\'Content-Type\':\'application/json\'},\n    body: JSON.stringify({teacher_name:name, proforma})\n  });\n  const data = await res.json();\n  if(data.success){ showToast(\'↩ \'+data.message,\'info\'); await loadTeachers(); await loadStats(); }\n  else showToast(\'❌ \'+(data.error||\'Reset failed.\'),\'error\');\n}\n\n/* ── Excel export ── */\nfunction exportExcel(type, filter, status){\n  const url = `/api/admin/export?type=${type}&filter=${encodeURIComponent(filter)}&status=${status}`;\n  window.open(url,\'_blank\');\n  showToast(\'📥 Excel download started.\',\'success\');\n}\n\nfunction showExportModal(){\n  // Populate proforma / school dropdowns\n  updateExpFilter2();\n  document.getElementById(\'exportModal\').classList.add(\'open\');\n}\n\nfunction updateExpFilter(){\n  const type = document.getElementById(\'expType\').value;\n  const sel  = document.getElementById(\'expFilter\');\n  sel.style.display = type===\'all\'?\'none\':\'inline-block\';\n  sel.innerHTML = \'<option value="">— Select —</option>\';\n  if(type===\'proforma\'){\n    [\'PROFORMA I\',\'PROFORMA II\',\'PROFORMA III\',\'PROFORMA IV\',\'PROFORMA V\',\'PROFORMA VI\',\'PROFORMA VII\']\n      .forEach(p=>sel.insertAdjacentHTML(\'beforeend\',`<option>${p}</option>`));\n  } else if(type===\'school\'){\n    allSchools.forEach(s=>sel.insertAdjacentHTML(\'beforeend\',`<option>${s}</option>`));\n  }\n}\n\nfunction updateExpFilter2(){\n  const type = document.getElementById(\'expType2\').value;\n  const grp  = document.getElementById(\'expFilterGroup2\');\n  const sel  = document.getElementById(\'expFilter2\');\n  grp.style.display = type===\'all\'?\'none\':\'block\';\n  sel.innerHTML = \'<option value="">— Select —</option>\';\n  if(type===\'proforma\'){\n    [\'PROFORMA I\',\'PROFORMA II\',\'PROFORMA III\',\'PROFORMA IV\',\'PROFORMA V\',\'PROFORMA VI\',\'PROFORMA VII\']\n      .forEach(p=>sel.insertAdjacentHTML(\'beforeend\',`<option>${p}</option>`));\n  } else if(type===\'school\'){\n    allSchools.forEach(s=>sel.insertAdjacentHTML(\'beforeend\',`<option>${s}</option>`));\n  }\n}\n\nfunction downloadExport(){\n  const type   = document.getElementById(\'expType\').value;\n  const filter = document.getElementById(\'expFilter\').value||\'\';\n  const status = document.getElementById(\'expStatus\').value||\'\';\n  exportExcel(type, filter, status);\n}\n\nfunction downloadExport2(){\n  const type   = document.getElementById(\'expType2\').value;\n  const filter = document.getElementById(\'expFilter2\').value||\'\';\n  const status = document.getElementById(\'expStatus2\').value||\'\';\n  exportExcel(type, filter, status);\n  document.getElementById(\'exportModal\').classList.remove(\'open\');\n}\n\n/* ── Logs ── */\nasync function loadLogs(){\n  const res  = await fetch(\'/api/admin/logs?limit=50\');\n  const data = await res.json();\n  const logs = data.logs||[];\n  const tbody = document.getElementById(\'logTbody\');\n  if(!logs.length){\n    tbody.innerHTML=\'<tr><td colspan="6" style="text-align:center;color:#aaa;padding:14px">No activity yet.</td></tr>\';\n    return;\n  }\n  tbody.innerHTML = logs.map(l=>{\n    const aColor = l.action.includes(\'VERIFY\')?\'#2e7d32\':l.action.includes(\'UPDATE\')?\'#1565c0\':l.action.includes(\'LOGIN\')?\'#6a1b9a\':\'#e65100\';\n    return `<tr>\n      <td style="font-size:.77rem;color:#777;white-space:nowrap">${l.timestamp}</td>\n      <td><span style="background:${aColor}20;color:${aColor};padding:3px 9px;border-radius:10px;font-size:.74rem;font-weight:700">${l.action}</span></td>\n      <td style="font-size:.8rem;font-weight:600">${esc(l.teacher_name||\'\')}</td>\n      <td style="font-size:.78rem;color:#777">${l.proforma||\'\'}</td>\n      <td style="font-size:.78rem;color:#777">${esc(l.school||\'\')}</td>\n      <td style="font-size:.77rem;color:#999;max-width:200px;word-break:break-word">${esc(l.details||\'\')}</td>\n    </tr>`;\n  }).join(\'\');\n}\n\n/* ── Utilities ── */\nlet toastTimer;\nfunction showToast(msg,type=\'success\'){\n  const el=document.getElementById(\'toast\');\n  el.textContent=msg; el.className=`toast ${type} show`;\n  clearTimeout(toastTimer);\n  toastTimer=setTimeout(()=>el.className=\'toast\',4000);\n}\n\nfunction esc(s){\n  if(s==null) return \'\';\n  return String(s).replace(/&/g,\'&amp;\').replace(/</g,\'&lt;\').replace(/>/g,\'&gt;\').replace(/"/g,\'&quot;\');\n}\n\n// Close modals on backdrop click\ndocument.getElementById(\'teacherModal\').addEventListener(\'click\',e=>{ if(e.target===e.currentTarget) closeModal(); });\ndocument.getElementById(\'exportModal\').addEventListener(\'click\',e=>{ if(e.target===e.currentTarget) document.getElementById(\'exportModal\').classList.remove(\'open\'); });\n</script>\n</body>\n</html>\n'

