# ── TEACHER LOGIN ──────────────────────────────────────────────────────
@app.route("/teacher/login", methods=["GET", "POST"])
def teacher_login():
    if request.method == "GET":
        schools = get_schools()
        return render_template_string(TEACHER_LOGIN_HTML, schools=schools)

    data   = request.get_json()
    school = (data.get("school") or "").strip()
    dob    = (data.get("dob") or "").strip()

    if not school or not dob:
        return jsonify({"error": "Please select your school and enter your date of birth."}), 400

    teachers = load_teachers()
    matched = [t for t in teachers
               if t.get("school","").strip() == school
               and dob_matches(t.get("dob",""), dob)]

    if not matched:
        return jsonify({"error":
            "No teacher found with this school and date of birth. "
            "Please check the details and try again."}), 404

    # Store teacher identifiers in session
    session["teacher_ids"] = [
        {"teacher_name": t["teacher_name"], "proforma": t["proforma"]}
        for t in matched
    ]
    session["teacher_school"] = school
    log_activity("LOGIN", matched[0]["teacher_name"], matched[0]["proforma"],
                 school, f"DOB login successful — {len(matched)} record(s)")
    return jsonify({"success": True, "count": len(matched)})

