@app.route("/api/teacher/update", methods=["POST"])
@teacher_required
def api_teacher_update():
    data          = request.get_json()
    teacher_name  = (data.get("teacher_name") or "").strip()
    proforma      = (data.get("proforma") or "").strip()
    updated_fields = data.get("fields", {})

    # Verify this teacher belongs to current session
    ids = session.get("teacher_ids", [])
    allowed = any(t["teacher_name"] == teacher_name and t["proforma"] == proforma
                  for t in ids)
    if not allowed:
        return jsonify({"error": "Unauthorized."}), 403

    # Remove protected fields
    for f in list(updated_fields.keys()):
        if f in PROTECTED_FIELDS:
            del updated_fields[f]

    if not updated_fields:
        return jsonify({"error": "No changes detected."}), 400

    teachers = load_teachers()
    now = datetime.datetime.now().strftime("%d/%m/%Y %H:%M:%S")
    changes_log = []

    for t in teachers:
        if t["teacher_name"] == teacher_name and t["proforma"] == proforma:
            history_entry = {"timestamp": now, "updated_by": teacher_name, "changes": {}}
            for k, v in updated_fields.items():
                old = t.get(k, "")
                if str(old).strip() != str(v).strip():
                    history_entry["changes"][k] = {"old": str(old), "new": str(v),
                                                    "label": FIELD_LABELS.get(k, k)}
                    t[k] = v
                    changes_log.append(f"{FIELD_LABELS.get(k,k)}: {old} → {v}")
            if history_entry["changes"]:
                if not isinstance(t.get("change_history"), list):
                    t["change_history"] = []
                t["change_history"].append(history_entry)
            t["status"]       = "UPDATED"
            t["last_updated"] = now
            t["updated_by"]   = teacher_name
            break

    save_teachers(teachers)
    school = session.get("teacher_school", "")
    log_activity("UPDATE", teacher_name, proforma, school,
                 "; ".join(changes_log))
    return jsonify({"success": True,
                    "message": f"Data updated successfully for {teacher_name}.",
                    "timestamp": now})

