@app.route("/api/admin/stats")
@admin_required
def api_admin_stats():
    teachers = load_teachers()
    total    = len(teachers)
    verified = sum(1 for t in teachers if t.get("status") == "VERIFIED")
    updated  = sum(1 for t in teachers if t.get("status") == "UPDATED")
    pending  = total - verified - updated

    # Per-proforma breakdown
    proforma_stats = {}
    for t in teachers:
        p = t.get("proforma", "")
        if p not in proforma_stats:
            proforma_stats[p] = {"total": 0, "verified": 0, "updated": 0, "pending": 0}
        proforma_stats[p]["total"] += 1
        s = t.get("status", "PENDING")
        proforma_stats[p][s.lower()] += 1

    # Per-school breakdown
    school_stats = {}
    for t in teachers:
        s = t.get("school", "Unknown")
        if s not in school_stats:
            school_stats[s] = {"total": 0, "verified": 0, "updated": 0, "pending": 0}
        school_stats[s]["total"] += 1
        st = t.get("status", "PENDING")
        school_stats[s][st.lower()] += 1

    return jsonify({
        "total": total, "verified": verified,
        "updated": updated, "pending": pending,
        "proforma_stats": proforma_stats,
        "school_stats": school_stats,
    })

