    proforma      = (data.get("proforma") or "").strip()
    updated_fields = data.get("fields", {})
    new_status    = data.get("status", "")

    teachers = load_teachers()
    now = datetime.datetime.now().strftime("%d/%m/%Y %H:%M:%S")
    changes_log = []
    admin = session.get("admin_user", "Admin")

