# ── EXCEL EXPORT ───────────────────────────────────────────────────────
@app.route("/api/admin/export")
@admin_required
def api_admin_export():
    export_type = request.args.get("type", "all")   # all | proforma | school
    filter_val  = request.args.get("filter", "")
    status_fil  = request.args.get("status", "")

    teachers = load_teachers()
    if export_type == "proforma" and filter_val:
        teachers = [t for t in teachers if t.get("proforma") == filter_val]
    elif export_type == "school" and filter_val:
        teachers = [t for t in teachers if t.get("school", "").strip() == filter_val]
    if status_fil:
        teachers = [t for t in teachers if t.get("status", "PENDING") == status_fil]

    wb  = _build_export_excel(teachers, export_type, filter_val, status_fil)
    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)

    fname = f"PROFORMA_CHIKITI_{datetime.datetime.now().strftime('%d%m%Y_%H%M')}.xlsx"
    log_activity("ADMIN_EXPORT", "ADMIN", "ALL", "", f"Exported {len(teachers)} records", "ADMIN")
    return send_file(buf, as_attachment=True, download_name=fname,
                     mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")

def _build_export_excel(teachers, export_type, filter_val, status_fil):
    from collections import defaultdict
    wb = openpyxl.Workbook()
    wb.remove(wb.active)

    NAVY   = "0D2366"; STEEL  = "1F4E79"; SKY    = "DCE6F1"
    GREEN  = "E8F5E9"; AMBER  = "FFF9C4"; WHITE  = "FFFFFF"
    GREY   = "F5F5F5"
    MED    = Side(border_style="medium", color="000000")
    THIN   = Side(border_style="thin",   color="000000")
    HAIR   = Side(border_style="hair",   color="AAAAAA")

    # Group by proforma
    by_pf = defaultdict(list)
    for t in teachers:
        by_pf[t.get("proforma", "OTHER")].append(t)

    PROFORMA_ORDER = ["PROFORMA I","PROFORMA II","PROFORMA III",
                      "PROFORMA IV","PROFORMA V","PROFORMA VI","PROFORMA VII"]
    keys_order = [p for p in PROFORMA_ORDER if p in by_pf] + \
                 [p for p in by_pf if p not in PROFORMA_ORDER]

    # Proforma-specific columns
    P12_COLS = ["sl_no","district","teacher_name","school",
                "general_qualification","date_general_result",
                "training_qualification","date_training_result",
                "otet","date_otet","category","dob",
                "date_first_appt_ss","date_regular_teacher",
                "notification_no","rank","date_superannuation",
                "dp_cp_vigilance","idt_ra","date_joining_district","remark",
                "status","last_updated"]
    P345_COLS = P12_COLS[:16] + ["date_joining_levelVB"] + P12_COLS[16:]
    P67_COLS  = ["sl_no","district","teacher_name","school",
                 "general_qualification","date_passing",
                 "training_qualification","date_training_passing",
                 "otet","date_otet","category","dob",
                 "date_first_appt_ss","date_regular_teacher",
                 "notification_no","rank","date_joining_levelIV",
                 "date_superannuation","idt_ra","date_joining_district",
                 "dp_cp_vigilance","remark","status","last_updated"]
    COL_MAP = {
        "PROFORMA I": P12_COLS, "PROFORMA II": P12_COLS,
        "PROFORMA III": P345_COLS, "PROFORMA IV": P345_COLS, "PROFORMA V": P345_COLS,
        "PROFORMA VI": P67_COLS, "PROFORMA VII": P67_COLS,
    }

    # PROFORMA titles
    TITLES = {
        "PROFORMA I":   "LIST OF LEVEL-V(A) ASST. TEACHERS (MATRIC/+2 WITH CT/B.Ed WITH OTET-I)",
        "PROFORMA II":  "LIST OF LEVEL-V(A) ASST. TEACHERS (GRADUATE WITH CT/B.Ed AND PASSED OTET-II)",
        "PROFORMA III": "LIST OF LEVEL-V(B) SENIOR TEACHERS, ELEMENTARY CADRE (CATEGORY-I)",
        "PROFORMA IV":  "LIST OF LEVEL-V(B) SENIOR TEACHERS (CATEGORY-II, GRADUATE SCIENCE)",
        "PROFORMA V":   "LIST OF LEVEL-V(B) SENIOR TEACHERS (CATEGORY-II, GRADUATE ARTS)",
        "PROFORMA VI":  "LIST OF LEVEL-IV (GRADUATE TEACHER) ELEMENTARY CADRE",
        "PROFORMA VII": "LIST OF LEVEL-IV (HM OF PS) ELEMENTARY CADRE",
    }

    for pf in keys_order:
        rows = by_pf[pf]
        if not rows: continue
        ws   = wb.create_sheet(title=pf[:31])
        cols = COL_MAP.get(pf, P12_COLS)
        ncols = len(cols)

        # Title row
        ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=ncols)
        tc = ws.cell(1, 1, TITLES.get(pf, pf))
        tc.font      = Font(name="Times New Roman", bold=True, size=10, color="FFFFFF")
        tc.fill      = PatternFill("solid", fgColor=NAVY)
        tc.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        ws.row_dimensions[1].height = 30

        # Header row
        for ci, col in enumerate(cols, 1):
            hc = ws.cell(2, ci, FIELD_LABELS.get(col, col))
            hc.font      = Font(name="Times New Roman", bold=True, size=8, color="FFFFFF")
            hc.fill      = PatternFill("solid", fgColor=STEEL)
            hc.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
            hc.border    = Border(left=THIN, right=THIN, top=MED, bottom=MED)
        ws.row_dimensions[2].height = 35

        # Data rows
        for idx, rec in enumerate(rows, 1):
            wr   = idx + 2
            stat = rec.get("status", "PENDING")
            bg   = GREEN if stat == "VERIFIED" else AMBER if stat == "UPDATED" else WHITE
            alt  = "EFF3FB" if idx % 2 == 0 else WHITE
            fill = bg if stat != "PENDING" else alt

            for ci, col in enumerate(cols, 1):
                val  = rec.get(col, "")
                cell = ws.cell(wr, ci, val)
                cell.font      = Font(name="Times New Roman", size=8)
                cell.fill      = PatternFill("solid", fgColor=fill)
                cell.alignment = Alignment(horizontal="center" if ci==1 else "left",
                                           vertical="center", wrap_text=True)
                cell.border    = Border(left=THIN, right=THIN, top=HAIR, bottom=HAIR)
            ws.row_dimensions[wr].height = 18

        # Column widths
        col_widths = {"teacher_name": 22, "school": 28, "notification_no": 22,
                      "remark": 18, "district": 18, "sl_no": 5,
                      "status": 11, "last_updated": 18}
        for ci, col in enumerate(cols, 1):
            ws.column_dimensions[get_column_letter(ci)].width = col_widths.get(col, 12)

        ws.freeze_panes = "C3"
        ws.sheet_view.showGridLines = False

    # Summary sheet
    ws_sum = wb.create_sheet("SUMMARY", 0)
    ws_sum.column_dimensions["A"].width = 22
    ws_sum.column_dimensions["B"].width = 10
    ws_sum.column_dimensions["C"].width = 10
    ws_sum.column_dimensions["D"].width = 10
    ws_sum.column_dimensions["E"].width = 10
    ws_sum.column_dimensions["F"].width = 10

    # Summary header
    ws_sum.merge_cells("A1:F1")
    th = ws_sum.cell(1, 1, "TEACHER VERIFICATION SUMMARY — CHIKITI BLOCK 2026")
    th.font      = Font(name="Arial", bold=True, size=12, color="FFFFFF")
    th.fill      = PatternFill("solid", fgColor=NAVY)
    th.alignment = Alignment(horizontal="center", vertical="center")
    ws_sum.row_dimensions[1].height = 35

    hdrs = ["Proforma", "Total", "Verified", "Updated", "Pending", "% Done"]
    for ci, h in enumerate(hdrs, 1):
        hc = ws_sum.cell(2, ci, h)
        hc.font      = Font(name="Arial", bold=True, size=9, color="FFFFFF")
        hc.fill      = PatternFill("solid", fgColor=STEEL)
        hc.alignment = Alignment(horizontal="center")
        hc.border    = Border(left=THIN, right=THIN, top=MED, bottom=MED)

    row_idx = 3
    grand = [0, 0, 0, 0]
    for pf in keys_order:
        rows = by_pf[pf]
        tot = len(rows)
        ver = sum(1 for t in rows if t.get("status") == "VERIFIED")
        upd = sum(1 for t in rows if t.get("status") == "UPDATED")
        pen = tot - ver - upd
        pct = f"{round((ver+upd)/tot*100)}%" if tot else "0%"
        grand[0] += tot; grand[1] += ver; grand[2] += upd; grand[3] += pen
        vals = [pf, tot, ver, upd, pen, pct]
        alt_bg = "F0F4FF" if row_idx % 2 == 0 else "FFFFFF"
        for ci, v in enumerate(vals, 1):
            c = ws_sum.cell(row_idx, ci, v)
            c.font      = Font(name="Arial", size=9)
            c.fill      = PatternFill("solid", fgColor=alt_bg)
            c.alignment = Alignment(horizontal="center" if ci > 1 else "left")
            c.border    = Border(left=THIN, right=THIN, top=HAIR, bottom=HAIR)
        row_idx += 1

    # Grand total
    g_pct = f"{round((grand[1]+grand[2])/grand[0]*100)}%" if grand[0] else "0%"
    gvals = ["TOTAL", grand[0], grand[1], grand[2], grand[3], g_pct]
    for ci, v in enumerate(gvals, 1):
        c = ws_sum.cell(row_idx, ci, v)
        c.font      = Font(name="Arial", bold=True, size=9, color="FFFFFF")
        c.fill      = PatternFill("solid", fgColor=NAVY)
        c.alignment = Alignment(horizontal="center" if ci > 1 else "left")
        c.border    = Border(left=MED, right=MED, top=MED, bottom=MED)

    # Export metadata
    row_idx += 2
    ws_sum.cell(row_idx, 1, "Export Date:").font = Font(bold=True, size=8)
    ws_sum.cell(row_idx, 2, datetime.datetime.now().strftime("%d/%m/%Y %H:%M")).font = Font(size=8)
    ws_sum.cell(row_idx+1, 1, "Filter:").font = Font(bold=True, size=8)
    ws_sum.cell(row_idx+1, 2, f"{export_type}: {filter_val or 'ALL'}").font = Font(size=8)

    return wb

