@app.route("/health")
def health():
    teachers = load_teachers()
    return jsonify({
        "status": "ok", "teachers": len(teachers),
        "time": datetime.datetime.now().strftime("%d/%m/%Y %H:%M:%S"),
        "data_path": DATA_PATH,
        "data_exists": os.path.exists(DATA_PATH),
        "base_dir": BASE_DIR
    })

